/**
 * 만세력 JavaScript 라이브러리 타입 정의
 * Korean Lunar Calendar (만세력) Type Definitions
 */
/**
 * 유효하지 않은 날짜 에러
 */
class InvalidDateError extends Error {
    constructor(message) {
        super(message);
        this.name = 'InvalidDateError';
    }
}
/**
 * 지원 범위 밖 에러
 */
class OutOfRangeError extends Error {
    constructor(year) {
        super(`Year ${year} is out of supported range (1900~2050)`);
        this.name = 'OutOfRangeError';
    }
}

/**
 * 범위 검증 유틸리티
 */
/**
 * 지원 범위 확인
 * @param year 확인할 연도
 * @returns 지원 여부 (1900~2050)
 */
function isSupportedYear(year) {
    return year >= 1900 && year <= 2050;
}
/**
 * 지원 연도 범위 조회
 * @returns { min, max } 지원 범위
 */
function getSupportedRange() {
    return { min: 1900, max: 2050 };
}

/**
 * 압축된 양력 → 음력 변환 인덱스
 *
 * ⚠️ 이 파일은 자동 생성됩니다. 직접 수정하지 마세요.
 * 생성: scripts/compress-date-index.ts
 */
// 상수
const BASE_JD = 2415021;
const DAY_PILLAR_EPOCH = 2415011;
const START_YEAR = 1900;
const END_YEAR = 2050;
const TOTAL_MONTHS = 1812;
