const JD_B64 = '';
const COUNT_B64 = '';
const DATA_B64 = '';
// 디코딩된 데이터 캐시
let _jdOffsets = null;
let _countBytes = null;
let _dataBytes = null;
let _dayOffsets = null;
function b64ToBytes(b64) {
    const bin = atob(b64);
    const bytes = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++)
        bytes[i] = bin.charCodeAt(i);
    return bytes;
}
function getJDOffsets() {
    if (!_jdOffsets)
        _jdOffsets = new Uint16Array(b64ToBytes(JD_B64).buffer);
    return _jdOffsets;
}
function getCountBytes() {
    if (!_countBytes)
        _countBytes = b64ToBytes(COUNT_B64);
    return _countBytes;
}
function getDataBytes() {
    if (!_dataBytes)
        _dataBytes = b64ToBytes(DATA_B64);
    return _dataBytes;
}
function getDayCount(idx) {
    const byteIdx = idx >>> 2;
    const bitOffset = (idx & 3) << 1;
    return ((getCountBytes()[byteIdx] >> bitOffset) & 3) + 28;
}
function getDayOffsets() {
    if (!_dayOffsets) {
        _dayOffsets = [0];
        for (let i = 0; i < TOTAL_MONTHS; i++) {
            _dayOffsets.push(_dayOffsets[i] + getDayCount(i));
        }
    }
    return _dayOffsets;
}
function decodeEntry(packed, year, month, day, jd) {
    const lunarYearOffset = packed & 3;
    const lunarYear = lunarYearOffset === 0 ? year : lunarYearOffset === 1 ? year - 1 : year + 1;
    return {
        jd,
        solar: { year, month, day },
        lunar: {
            year: lunarYear,
            month: ((packed >> 2) & 0xf) + 1,
            day: ((packed >> 6) & 0x1f) + 1,
            isLeap: ((packed >> 11) & 1) === 1,
        },
        gapja: {
            yearPillarId: (packed >> 12) & 0x3f,
            monthPillarId: (packed >> 18) & 0x3f,
            dayPillarId: (jd - DAY_PILLAR_EPOCH) % 60,
        },
    };
}
const _cache = new Map();
function getMonthlyIndex(year, month) {
    if (year < START_YEAR || year > END_YEAR || month < 1 || month > 12)
        return undefined;
    const key = `${year}-${String(month).padStart(2, '0')}`;
    const cached = _cache.get(key);
    if (cached)
        return cached;
    const idx = (year - START_YEAR) * 12 + month - 1;
    const dayCount = getDayCount(idx);
    const byteOffset = getDayOffsets()[idx] * 3;
    const startJD = BASE_JD + getJDOffsets()[idx];
    const data = getDataBytes();
    const entries = [];
    for (let d = 0; d < dayCount; d++) {
        const i = byteOffset + d * 3;
        const packed = data[i] | (data[i + 1] << 8) | (data[i + 2] << 16);
        entries.push(decodeEntry(packed, year, month, d + 1, startJD + d));
    }
    const result = { year, month, entries, startJD, endJD: startJD + dayCount - 1 };
    _cache.set(key, result);
    return result;
}
/** @deprecated getMonthlyIndex() 사용 권장 */
const SOLAR_TO_LUNAR_INDEX = new Proxy(new Map(), {
    get(target, prop) {
        if (prop === 'get')
            return (key) => getMonthlyIndex(+key.slice(0, 4), +key.slice(5, 7));
        if (prop === 'has')
            return (key) => {
                const y = +key.slice(0, 4), m = +key.slice(5, 7);
                return y >= START_YEAR && y <= END_YEAR && m >= 1 && m <= 12;
            };
        if (prop === 'keys')
            return function* () {
                for (let y = START_YEAR; y <= END_YEAR; y++)
                    for (let m = 1; m <= 12; m++)
                        yield `${y}-${String(m).padStart(2, '0')}`;
            };
        if (prop === 'size')
            return TOTAL_MONTHS;
        if (prop === Symbol.iterator)
            return function* () {
                for (let y = START_YEAR; y <= END_YEAR; y++)
                    for (let m = 1; m <= 12; m++) {
                        const key = `${y}-${String(m).padStart(2, '0')}`;
                        const idx = getMonthlyIndex(y, m);
                        if (idx)
                            yield [key, idx];
                    }
            };
        return Reflect.get(target, prop);
    },
});

