function elementDistribution(pillars) {
    const dist = { 목: 0, 화: 0, 토: 0, 금: 0, 수: 0 };
    for (const hangul of pillars) {
        const p = getPillarByHangul(hangul);
        if (!p)
            continue;
        dist[p.tiangan.element]++;
        dist[p.dizhi.element]++;
    }
    return dist;
}
